import os
import json
import csv
import hashlib
from datetime import datetime, timezone
from typing import Any, Dict, Optional, Tuple

from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub_v1


PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
FIRESTORE_COLLECTION = os.environ.get("FIRESTORE_COLLECTION", "ingestions")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "ingestion-events")
MAX_BYTES = int(os.environ.get("MAX_BYTES", "10485760"))  # 10MB default


_storage_client = storage.Client()
_firestore_client = firestore.Client()
_publisher = pubsub_v1.PublisherClient()
_topic_path = _publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)


def _utc_now_iso() -> str:
    return datetime.now(timezone.utc).isoformat()


def _sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def _safe_decode(data: bytes) -> str:
    try:
        return data.decode("utf-8")
    except Exception:
        return data.decode("utf-8", errors="replace")


def _parse_content(name: str, data: bytes) -> Dict[str, Any]:
    lower = name.lower()
    text = _safe_decode(data)

    if lower.endswith(".json"):
        try:
            obj = json.loads(text)
            return {"type": "json", "records": obj}
        except Exception as e:
            return {"type": "json", "error": str(e), "raw_preview": text[:2000]}

    if lower.endswith(".csv"):
        try:
            reader = csv.DictReader(text.splitlines())
            rows = []
            for i, row in enumerate(reader):
                if i >= 1000:
                    break
                rows.append(row)
            return {"type": "csv", "rows": rows, "truncated": len(rows) >= 1000}
        except Exception as e:
            return {"type": "csv", "error": str(e), "raw_preview": text[:2000]}

    return {"type": "text", "raw_preview": text[:4000]}


def _download_blob_bytes(bucket_name: str, object_name: str) -> Tuple[bytes, Dict[str, Any]]:
    bucket = _storage_client.bucket(bucket_name)
    blob = bucket.blob(object_name)
    blob.reload()

    meta = {
        "bucket": bucket_name,
        "name": object_name,
        "contentType": blob.content_type,
        "size": int(blob.size or 0),
        "md5Hash": blob.md5_hash,
        "crc32c": blob.crc32c,
        "generation": str(blob.generation) if blob.generation is not None else None,
        "metageneration": str(blob.metageneration) if blob.metageneration is not None else None,
        "updated": blob.updated.isoformat() if blob.updated else None,
        "timeCreated": blob.time_created.isoformat() if blob.time_created else None,
    }

    if meta["size"] > MAX_BYTES:
        raise ValueError(f"Object too large: {meta['size']} > {MAX_BYTES}")

    data = blob.download_as_bytes()
    return data, meta


def _write_firestore(doc_id: str, doc: Dict[str, Any]) -> None:
    _firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id).set(doc, merge=True)


def _publish_pubsub(message: Dict[str, Any], attributes: Optional[Dict[str, str]] = None) -> str:
    data = json.dumps(message, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    future = _publisher.publish(_topic_path, data=data, **(attributes or {}))
    return future.result()


def gcs_to_firestore_pubsub(event: Dict[str, Any], context: Any = None) -> Dict[str, Any]:
    bucket = event.get("bucket")
    name = event.get("name")
    if not bucket or not name:
        raise ValueError("Missing required event fields: bucket, name")

    content_type = event.get("contentType") or event.get("content_type")
    size = event.get("size")

    data, blob_meta = _download_blob_bytes(bucket, name)
    sha256 = _sha256_bytes(data)

    parsed = _parse_content(name, data)

    doc_id = sha256
    doc = {
        "ingestedAt": _utc_now_iso(),
        "source": {
            "event": {
                "bucket": bucket,
                "name": name,
                "contentType": content_type,
                "size": size,
                "timeCreated": event.get("timeCreated") or event.get("time_created"),
                "updated": event.get("updated"),
                "generation": event.get("generation"),
                "metageneration": event.get("metageneration"),
            },
            "blob": blob_meta,
        },
        "hashes": {"sha256": sha256},
        "parsed": parsed,
        "status": "INGESTED",
    }

    _write_firestore(doc_id, doc)

    pubsub_message = {
        "id": doc_id,
        "bucket": bucket,
        "name": name,
        "sha256": sha256,
        "collection": FIRESTORE_COLLECTION,
        "ingestedAt": doc["ingestedAt"],
        "contentType": blob_meta.get("contentType"),
        "size": blob_meta.get("size"),
        "status": doc["status"],
    }

    message_id = _publish_pubsub(
        pubsub_message,
        attributes={
            "bucket": str(bucket),
            "name": str(name),
            "sha256": str(sha256),
            "collection": str(FIRESTORE_COLLECTION),
        },
    )

    return {"ok": True, "firestoreDocId": doc_id, "pubsubMessageId": message_id}


